/**
 * Email notification adapter — delivers notifications via email.
 *
 * Provides template rendering per notification type, recipient validation,
 * and configurable retry behavior. Implements the NotificationAdapter interface
 * required by the notification system's event-driven architecture.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Email sender address (e.g. "noreply@taskflow.com"). */
  from: string;
  /** Optional reply-to address. */
  replyTo?: string;
  /** Maximum retry attempts for transient failures (default: 0). */
  maxRetries?: number;
}

export interface SentEmail {
  from: string;
  to: string;
  replyTo?: string;
  subject: string;
  body: string;
  sentAt: Date;
}

/**
 * A simple email template with subject and body formatters.
 * The `body` function receives the raw notification body and metadata.
 */
export interface EmailTemplate {
  subject: (payload: NotificationPayload) => string;
  body: (payload: NotificationPayload) => string;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Built-in templates keyed by NotificationType.
 * Each template wraps the notification content in a structured email format.
 */
const DEFAULT_TEMPLATES: Record<NotificationType, EmailTemplate> = {
  order_confirmation: {
    subject: (p) => `Order Confirmation — ${p.subject}`,
    body: (p) =>
      `Dear Customer,\n\nThank you for your order!\n\n${p.body}\n\nIf you have any questions, reply to this email.\n\nBest regards,\nTaskFlow Pro`,
  },
  order_status_update: {
    subject: (p) => `Order Status Update — ${p.subject}`,
    body: (p) =>
      `Dear Customer,\n\n${p.body}\n\nYou can track your order in your dashboard.\n\nBest regards,\nTaskFlow Pro`,
  },
  welcome: {
    subject: () => 'Welcome to TaskFlow Pro!',
    body: (p) =>
      `Hi ${p.metadata?.name ?? 'there'},\n\nWelcome to TaskFlow Pro! We're excited to have you on board.\n\n${p.body}\n\nBest regards,\nThe TaskFlow Pro Team`,
  },
  account_update: {
    subject: (p) => `Account Update — ${p.subject}`,
    body: (p) =>
      `Hello,\n\nYour account has been updated.\n\n${p.body}\n\nIf you did not make this change, please contact support immediately.\n\nBest regards,\nTaskFlow Pro`,
  },
  system_alert: {
    subject: (p) => `[Alert] ${p.subject}`,
    body: (p) =>
      `SYSTEM ALERT\n\n${p.body}\n\nThis is an automated message from TaskFlow Pro.`,
  },
};

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];
  private templates: Map<NotificationType, EmailTemplate> = new Map();

  constructor(private config: EmailConfig) {
    // Register all built-in templates
    for (const [type, template] of Object.entries(DEFAULT_TEMPLATES)) {
      this.templates.set(type as NotificationType, template);
    }
  }

  /**
   * Register or override a template for a specific notification type.
   */
  setTemplate(type: NotificationType, template: EmailTemplate): void {
    this.templates.set(type, template);
  }

  /**
   * Validate that a recipient string is a well-formed email address.
   */
  validateRecipient(recipient: string): boolean {
    return EMAIL_REGEX.test(recipient);
  }

  /**
   * Render a notification payload through the template for its type.
   * Returns the formatted subject and body. Falls back to the raw
   * payload values if no template is registered.
   */
  renderTemplate(payload: NotificationPayload): { subject: string; body: string } {
    const template = this.templates.get(payload.type);
    if (!template) {
      return { subject: payload.subject, body: payload.body };
    }
    return {
      subject: template.subject(payload),
      body: template.body(payload),
    };
  }

  /**
   * Send an email notification.
   *
   * 1. Validates the recipient email address.
   * 2. Renders the template for the notification type.
   * 3. Records the email and returns the result.
   *
   * Never throws — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!this.validateRecipient(payload.recipient)) {
      this.logger.warn(`Invalid recipient email: ${payload.recipient}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: 'email',
        error: `Invalid recipient email address: ${payload.recipient}`,
        deliveredAt: new Date(),
      };
    }

    const rendered = this.renderTemplate(payload);

    this.logger.info(`Sending email to ${payload.recipient}: ${rendered.subject}`);

    const email: SentEmail = {
      from: this.config.from,
      to: payload.recipient,
      replyTo: this.config.replyTo,
      subject: rendered.subject,
      body: rendered.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);

    return {
      success: true,
      notificationId: payload.id,
      channel: 'email',
      deliveredAt: email.sentAt,
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    recipient: 'alice@example.com',
    subject: 'Order #123',
    body: 'Widget x2. Total: $20.00',
    channel: 'email',
    ...overrides,
  };
}

describe('EmailNotificationAdapter', () => {
  let adapter: EmailNotificationAdapter;

  beforeEach(() => {
    adapter = new EmailNotificationAdapter({
      from: 'noreply@taskflow.com',
      replyTo: 'support@taskflow.com',
    });
  });

  describe('channel', () => {
    it('should report "email" as its channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('validateRecipient', () => {
    it('should accept valid email addresses', () => {
      expect(adapter.validateRecipient('alice@example.com')).toBe(true);
      expect(adapter.validateRecipient('bob+tag@sub.domain.co')).toBe(true);
    });

    it('should reject invalid email addresses', () => {
      expect(adapter.validateRecipient('')).toBe(false);
      expect(adapter.validateRecipient('not-an-email')).toBe(false);
      expect(adapter.validateRecipient('missing@')).toBe(false);
      expect(adapter.validateRecipient('@no-local.com')).toBe(false);
      expect(adapter.validateRecipient('spaces in@email.com')).toBe(false);
    });
  });

  describe('renderTemplate', () => {
    it('should render order_confirmation template', () => {
      const payload = makePayload({ type: 'order_confirmation' });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.subject).toContain('Order Confirmation');
      expect(rendered.body).toContain('Thank you for your order');
      expect(rendered.body).toContain('Widget x2');
      expect(rendered.body).toContain('TaskFlow Pro');
    });

    it('should render order_status_update template', () => {
      const payload = makePayload({
        type: 'order_status_update',
        subject: 'Order #123',
        body: 'Status changed from pending to confirmed.',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.subject).toContain('Order Status Update');
      expect(rendered.body).toContain('pending to confirmed');
      expect(rendered.body).toContain('track your order');
    });

    it('should render welcome template with name from metadata', () => {
      const payload = makePayload({
        type: 'welcome',
        body: 'Get started by creating a project.',
        metadata: { name: 'Alice' },
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.subject).toBe('Welcome to TaskFlow Pro!');
      expect(rendered.body).toContain('Hi Alice');
      expect(rendered.body).toContain('Get started by creating a project.');
    });

    it('should render welcome template without name', () => {
      const payload = makePayload({
        type: 'welcome',
        body: 'Get started.',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.body).toContain('Hi there');
    });

    it('should render account_update template', () => {
      const payload = makePayload({
        type: 'account_update',
        body: 'Your email was changed.',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.subject).toContain('Account Update');
      expect(rendered.body).toContain('contact support');
    });

    it('should render system_alert template', () => {
      const payload = makePayload({
        type: 'system_alert',
        subject: 'High CPU',
        body: 'CPU usage exceeded 90%.',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.subject).toBe('[Alert] High CPU');
      expect(rendered.body).toContain('SYSTEM ALERT');
      expect(rendered.body).toContain('CPU usage exceeded 90%');
    });

    it('should allow overriding a template', () => {
      adapter.setTemplate('welcome', {
        subject: () => 'Custom Welcome',
        body: (p) => `Custom body: ${p.body}`,
      });

      const payload = makePayload({ type: 'welcome', body: 'Hello!' });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.subject).toBe('Custom Welcome');
      expect(rendered.body).toBe('Custom body: Hello!');
    });
  });

  describe('send', () => {
    it('should send successfully with valid recipient', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should fail for invalid recipient email', async () => {
      const payload = makePayload({ recipient: 'not-an-email' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient email');
    });

    it('should record sent emails with correct fields', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const emails = adapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.from).toBe('noreply@taskflow.com');
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.replyTo).toBe('support@taskflow.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.body).toContain('Thank you for your order');
      expect(emails[0]?.sentAt).toBeInstanceOf(Date);
    });

    it('should not record email when recipient is invalid', async () => {
      await adapter.send(makePayload({ recipient: 'bad' }));
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should apply template rendering in sent email', async () => {
      const payload = makePayload({
        type: 'system_alert',
        subject: 'Disk Full',
        body: 'Disk at 95%.',
      });
      await adapter.send(payload);

      const emails = adapter.getSentEmails();
      expect(emails[0]?.subject).toBe('[Alert] Disk Full');
      expect(emails[0]?.body).toContain('SYSTEM ALERT');
    });

    it('should handle multiple sends independently', async () => {
      await adapter.send(makePayload({ id: 'n1', recipient: 'a@b.com' }));
      await adapter.send(makePayload({ id: 'n2', recipient: 'c@d.com' }));

      expect(adapter.getSentEmails()).toHaveLength(2);
    });
  });

  describe('clearSentEmails', () => {
    it('should clear the sent emails list', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('config without replyTo', () => {
    it('should leave replyTo undefined when not configured', async () => {
      const simpleAdapter = new EmailNotificationAdapter({ from: 'no-reply@test.com' });
      await simpleAdapter.send(makePayload());

      const emails = simpleAdapter.getSentEmails();
      expect(emails[0]?.replyTo).toBeUndefined();
    });
  });
});

